// Copyright (c) HashiCorp, Inc.// SPDX-License-Identifier: MPL-2.0package pluginimport ("bytes""context""io""net""net/rpc"hclog "github.com/hashicorp/go-hclog""github.com/hashicorp/go-plugin/internal/plugin""github.com/mitchellh/go-testing-interface""google.golang.org/grpc")// TestOptions allows specifying options that can affect the behavior of the// test tionstype TestOptions struct {//ServerStdout causes the given value to be used in place of a blank buffer//for RPCServer's StdoutServerStdout io.ReadCloser//ServerStderr causes the given value to be used in place of a blank buffer//for RPCServer's StderrServerStderr io.ReadCloser}// The testing file contains test helpers that you can use outside of// this package for making it easier to test plugins themselves.// TestConn is a helper  for returning a client and server// net.Conn connected to each other. TestConn(t testing.T) (net.Conn, net.Conn) {// Listen to any local port. This listener will be closed// after a single connection is established.l, err := net.Listen("tcp", "127.0.0.1:0")if err != nil {t.Fatalf("err: %s", err)}// t a goroutine to accept our client connectionvar serverConn net.ConndoneCh := make(chan struct{})go () {defer close(doneCh)defer l.Close()var err errorserverConn, err = l.Accept()if err != nil {t.Fatalf("err: %s", err)}}()// Connect to the serverclientConn, err := net.Dial("tcp", l.Addr().String())if err != nil {t.Fatalf("err: %s", err)}// Wait for the server side to acknowledge it has connected<-doneChurn clientConn, serverConn}// TestRPCConn returns a rpc client and server connected to each other. TestRPCConn(t testing.T) (*rpc.Client, *rpc.Server) {clientConn, serverConn := TestConn(t)server := rpc.NewServer()go server.ServeConn(serverConn)client := rpc.NewClient(clientConn)urn client, server}// TestPluginRPCConn returns a plugin RPC client and server that are connected// together and configured. TestPluginRPCConn(t testing.T, ps map[string]Plugin, opts *TestOptions) (*RPCClient, *RPCServer) {// Create two net.Conns we can use to shuttle our control connectionclientConn, serverConn := TestConn(t)// Start up the serverserver := &RPCServer{Plugins: ps, Stdout: new(bytes.Buffer), Stderr: new(bytes.Buffer)}if opts != nil {if opts.ServerStdout != nil {server.Stdout = opts.ServerStdout}if opts.ServerStderr != nil {server.Stderr = opts.ServerStderr}}go server.ServeConn(serverConn)// Connect the client to the serverclient, err := NewRPCClient(clientConn, ps)if err != nil {t.Fatalf("err: %s", err)}urn client, server}// TestGRPCConn returns a gRPC client conn and grpc server that are connected// together and configured. The register tion is used to register services// prior to the Serve call. This is used to test gRPC connections. TestGRPCConn(t testing.T, register (*grpc.Server)) (*grpc.ClientConn, *grpc.Server) {// Create a listenerl, err := net.Listen("tcp", "127.0.0.1:0")if err != nil {t.Fatalf("err: %s", err)}server := grpc.NewServer()register(server)go server.Serve(l)// Connect to the serverconn, err := grpc.Dial(l.Addr().String(),grpc.WithBlock(),grpc.WithInsecure())if err != nil {t.Fatalf("err: %s", err)}// Connection successful, close the listenerl.Close()return conn, server}// TestPluginGRPCConn returns a plugin gRPC client and server that are connected// together and configured. This is used to test gRPC connections. TestPluginGRPCConn(t testing.T, ps map[string]Plugin) (*GRPCClient, *GRPCServer) {// Create a listenerl, err := net.Listen("tcp", "127.0.0.1:0")if err != nil {t.Fatalf("err: %s", err)}// Start up the serverserver := &GRPCServer{Plugins: ps,DoneCh:  make(chan struct{}),Server:  DefaultGRPCServer,Stdout:  new(bytes.Buffer),Stderr:  new(bytes.Buffer),logger:  hclog.Default(),}if err := server.Init(); err != nil {t.Fatalf("err: %s", err)}go server.Serve(l)// Connect to the serverconn, err := grpc.Dial(l.Addr().String(),grpc.WithBlock(),grpc.WithInsecure())if err != nil {t.Fatalf("err: %s", err)}brokerGRPCClient := newGRPCBrokerClient(conn)broker := newGRPCBroker(brokerGRPCClient, nil, UnixSocketConfig{}, nil)go broker.Run()go brokerGRPCClient.StartStream()// Create the clientclient := &GRPCClient{Conn:conn,Plugins:ps,broker:broker,doneCtx:context.Background(),controller: plugin.NewGRPCControllerClient(conn),}return client, server}